mapper.select:
SELECT f.id, f.student_name AS studentName, f.student_no AS studentId, f.feedback_type AS type, f.title, f.content, f.feedback_status AS status, f.reply_content AS reply, (SELECT u.full_name FROM users u WHERE u.id = f.replied_by) AS repliedBy, f.replied_at AS repliedAt, f.created_at AS createdAt FROM user_feedbacks f WHERE f.deleted_at IS NULL
AND (f.student_name LIKE CONCAT('%', #{search}, '%') OR f.student_no LIKE CONCAT('%', #{search}, '%') OR f.title LIKE CONCAT('%', #{search}, '%'))
AND f.feedback_type = #{type}
AND f.feedback_status = #{status}
ORDER BY f.created_at DESC
